Create Customer.code:
// Create a customer via the QuickBooks REST API.
// The intuit adaptor exposes a thin HTTP wrapper (http.post / http.get).
http.post(`/v3/company/${$.configuration.realmId}/customer`, {
  DisplayName: $.data.name,
  PrimaryEmailAddr: { Address: $.data.email },
  PrimaryPhone:     { FreeFormNumber: $.data.phone },
});

Create Estimate.code:
// Create an estimate.
http.post(`/v3/company/${$.configuration.realmId}/estimate`, {
  CustomerRef: { value: $.data.customerId },
  Line: $.data.lineItems,
});

Create Expense.code:
// Create an expense (Purchase with PaymentType=Cash/Check/CreditCard).
http.post(`/v3/company/${$.configuration.realmId}/purchase`, {
  PaymentType: 'Cash',
  AccountRef:  { value: $.data.accountId },
  Line: $.data.lineItems,
});

Create Invoice.code:
// Create an invoice.
http.post(`/v3/company/${$.configuration.realmId}/invoice`, {
  CustomerRef: { value: $.data.customerId },
  Line: $.data.lineItems,
});

Create Payment.code:
// Record a payment against an invoice.
http.post(`/v3/company/${$.configuration.realmId}/payment`, {
  CustomerRef: { value: $.data.customerId },
  TotalAmt:    $.data.amount,
  Line: [
    {
      Amount: $.data.amount,
      LinkedTxn: [{ TxnId: $.data.invoiceId, TxnType: 'Invoice' }],
    },
  ],
});

Create Sales Receipt.code:
// Create a sales receipt.
http.post(`/v3/company/${$.configuration.realmId}/salesreceipt`, {
  CustomerRef: { value: $.data.customerId },
  Line: $.data.lineItems,
});

Send Invoice.code:
// Send an existing invoice by email.
// The sendTo querystring overrides the customer's email on file.
http.post(
  `/v3/company/${$.configuration.realmId}/invoice/${$.data.invoiceId}/send?sendTo=${encodeURIComponent($.data.email)}`,
  // QuickBooks requires an empty JSON body on this endpoint.
  {}
);

Update Customer.code:
// Sparse update on a customer (Id + SyncToken required).
http.post(`/v3/company/${$.configuration.realmId}/customer`, {
  Id:        $.data.customerId,
  SyncToken: $.data.syncToken,
  sparse:    true,
  PrimaryEmailAddr: { Address: $.data.email },
});

Find Customer.code:
// Look up a customer with a QuickBooks query.
// Quote string literals with single quotes.
http.get(
  `/v3/company/${$.configuration.realmId}/query` +
  `?query=` + encodeURIComponent(
    `select * from Customer where PrimaryEmailAddr = '${$.data.email}'`
  )
);

Find Invoice.code:
// Look up an invoice by DocNumber.
http.get(
  `/v3/company/${$.configuration.realmId}/query` +
  `?query=` + encodeURIComponent(
    `select * from Invoice where DocNumber = '${$.data.docNumber}'`
  )
);
